1310 Value *SCEVExpander::visitAddRecExpr(const SCEVAddRecExpr *S) {
1311   // In canonical mode we compute the addrec as an expression of a canonical IV
1312   // using evaluateAtIteration and expand the resulting SCEV expression. This
1313   // way we avoid introducing new IVs to carry on the computation of the addrec
1314   // throughout the loop.
1315   //
1316   // For nested addrecs evaluateAtIteration might need a canonical IV of a
1317   // type wider than the addrec itself. Emitting a canonical IV of the
1318   // proper type might produce non-legal types, for example expanding an i64
1319   // {0,+,2,+,1} addrec would need an i65 canonical IV. To avoid this just fall
1320   // back to non-canonical mode for nested addrecs.
1321   if (!CanonicalMode || (S->getNumOperands() > 2))
1322     return expandAddRecExprLiterally(S);
1323 
1324   Type *Ty = SE.getEffectiveSCEVType(S->getType());
1325   const Loop *L = S->getLoop();
1326 
1327   // First check for an existing canonical IV in a suitable type.
1328   PHINode *CanonicalIV = nullptr;
1329   if (PHINode *PN = L->getCanonicalInductionVariable())
1330     if (SE.getTypeSizeInBits(PN->getType()) >= SE.getTypeSizeInBits(Ty))
1331       CanonicalIV = PN;
1332 
1333   // Rewrite an AddRec in terms of the canonical induction variable, if
1334   // its type is more narrow.
1335   if (CanonicalIV &&
1336       SE.getTypeSizeInBits(CanonicalIV->getType()) > SE.getTypeSizeInBits(Ty) &&
1337       !S->getType()->isPointerTy()) {
